#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

long long stirling[101][101];

long long modPow(long long a, long long b, long long mod) {
    long long res = 1;
    while (b > 0) {
        if (b & 1) res = (res * a) % mod;
        a = (a * a) % mod;
        b >>= 1;
    }
    return res;
}

void calculateStirling(int n) {
    for (int i = 0; i <= n; i++) {
        stirling[i][0] = 0;
        stirling[i][i] = 1;
    }
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j < i; j++) {
            stirling[i][j] = (stirling[i - 1][j - 1] + j * stirling[i - 1][j]) % MOD;
        }
    }
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, k, m;
        scanf("%d %d %d", &n, &k, &m);
        MOD = m;
        calculateStirling(n);
        long long ans = 0;
        for (int i = 1; i <= n; i++) {
            ans = (ans + modPow(2, i * (n - i), m) * stirling[n][i]) % m;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

